const data = $input.first().json;

const execution = data.execution ?? {};
const workflow = data.workflow ?? {};
const error = execution.error ?? data.error ?? {};

return [
  {
    json: {
      alert_type: "workflow_error",
      workflow_id: workflow.id ?? null,
      workflow_name: workflow.name ?? "Unknown workflow",
      execution_id: execution.id ?? null,
      execution_url: execution.url ?? null,
      execution_mode: execution.mode ?? null,
      failed_node: execution.lastNodeExecuted ?? null,
      error_message:
        error.message ??
        data.message ??
        "Unknown workflow error",
      error_stack: error.stack ?? null,
      occurred_at: new Date().toISOString(),
      status: "unresolved",
    },
  },
];
